mapper.select:
SELECT CT.COMPANY_CD , (CASE WHEN COMPANY_CD = #{ses.manageCd} THEN (SELECT CM.BUYER_NM FROM STOCOGCM CM WHERE CM.GATE_CD = CT.GATE_CD AND CM.BUYER_CD = CT.COMPANY_CD AND CM.DEL_FLAG = '0') ELSE GETCUSTNAME(GATE_CD, COMPANY_CD) END) AS COMPANY_NM , CT.DOC_TYPE , CT.PREFIX_STRING , CT.YEAR_FLAG , CT.MONTH_FLAG , CT.DAY_FLAG , CT.YEAR_TYPE , CT.CURRENT_VAL , CT.CURRENT_NUM , CT.USE_FLAG , CT.MOD_USER_ID , GETUSERNAME(CT.GATE_CD, CT.MOD_USER_ID, #{ses.langCd}) AS MOD_USER_NM , (CT.MOD_DATE, 'yyyyMMdd') AS MOD_DATE , 'U' AS DB_FLAG FROM STOCDNCT CT WHERE CT.GATE_CD = #{ses.gateCd} AND CT.DEL_FLAG = '0'
AND CT.COMPANY_CD = #{COMPANY_CD}
AND CT.DOC_TYPE = #{DOC_TYPE}
AND CT.PREFIX_STRING like '%' #{PREFIX_STRING} '%'
ORDER BY CT.COMPANY_CD, CT.DOC_TYPE

SELECT COUNT(DOC_TYPE)
  FROM STOCDNCT
 WHERE GATE_CD = #{ses.gateCd}
   AND COMPANY_CD = #{COMPANY_CD}
   AND DOC_TYPE = #{DOC_TYPE}

mapper.insert:
INSERT INTO STOCDNCT  (
      GATE_CD
    , COMPANY_CD
    , DOC_TYPE
    , PREFIX_STRING
    , CURRENT_NUM
    , YEAR_FLAG
    , MONTH_FLAG
    , DAY_FLAG
    , YEAR_TYPE
    , CURRENT_VAL
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , START_NUM
    , END_NUM2
    , DEL_FLAG
    , USE_FLAG
) VALUES (
      #{ses.gateCd}
    , #{COMPANY_CD}
    , #{DOC_TYPE}
    , #{PREFIX_STRING}

    , (#{PREFIX_STRING}
      (CASE WHEN #{YEAR_FLAG} = '1' THEN (CASE WHEN #{YEAR_TYPE} = '4' THEN TO_CHAR(SYSDATE, 'YYYY') ELSE TO_CHAR(SYSDATE, 'YY') END) ELSE '' END)
      (CASE WHEN #{MONTH_FLAG} = '1' THEN TO_CHAR(SYSDATE, 'MM') ELSE '' END)
      (CASE WHEN #{DAY_FLAG} = '1' THEN TO_CHAR(SYSDATE, 'DD') ELSE '' END)
      (#{CURRENT_VAL},''))


    , (CASE WHEN #{PREFIX_STRING} IS NULL THEN '' ELSE #{PREFIX_STRING} END
      (CASE WHEN #{YEAR_FLAG} = '1' THEN (CASE WHEN #{YEAR_TYPE} = '4' THEN SUBSTRING(CONVERT(VARCHAR(8), SYSDATETIME(), 112),1,4) ELSE SUBSTRING(CONVERT(VARCHAR(8), SYSDATETIME(), 112),3,2) END) ELSE '' END)
      (CASE WHEN #{MONTH_FLAG} = '1' THEN SUBSTRING(CONVERT(VARCHAR(8), SYSDATETIME(), 112),5,2) ELSE '' END)
      (CASE WHEN #{DAY_FLAG} = '1' THEN SUBSTRING(CONVERT(VARCHAR(8), SYSDATETIME(), 112),7,2) ELSE '' END)
      (#{CURRENT_VAL},''))

    , #{YEAR_FLAG}
    , #{MONTH_FLAG}
    , #{DAY_FLAG}
    , #{YEAR_TYPE}
    , #{CURRENT_VAL}
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}

    , TO_NUMBER(#{CURRENT_VAL})


    , CONVERT(INTEGER, #{CURRENT_VAL})

    , (SF_LPAD('9', SF_LENGTH(#{CURRENT_VAL}), '9'))
    , '0'
    , #{USE_FLAG}
)

